#!/usr/bin/env bash
# 1-10.sh — 稳定运营期：搭标签体系 + 跑复购 / 会员（1→10 精细化） SOP walkthrough for 微信私域运营 (企微 + 个人号 + 公众号 + 视频号 + 小程序 + 朋友圈 + 社群 全链路 — 引流 / 沉淀 / 触达 / 转化 / 复购 / 裂变).
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="微信私域运营 (企微 + 个人号 + 公众号 + 视频号 + 小程序 + 朋友圈 + 社群 全链路 — 引流 / 沉淀 / 触达 / 转化 / 复购 / 裂变)"
WORKFLOW="稳定运营期：搭标签体系 + 跑复购 / 会员（1→10 精细化）"

usage() {
  cat <<EOF
1-10.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./1-10.sh             # interactive
  ./1-10.sh --dry-run
  ./1-10.sh --json
  ./1-10.sh --explain
  ./1-10.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "稳定运营期：搭标签体系 + 跑复购 / 会员（1→10 精细化）" 工作流。

一句话: 私域闭环已跑通后，从「粗放运营、全员一套话术」到「有标签体系、按价值分层、靠会员 / 复购机制把单客价值做深」——这是私域从「能转化」到「ROI 算得正」的关键一跃。

入门 SOP 共 6 步, 失败模式自检 4 项。

相关心智模型:
  • 公私二分 / 流量自主权（mental model）: 私域人看一切流量的底层镜片是「这部分流量是租来的还是自己的」——租来的（公域）用一次付一次、平台控分发，自己的（私域）可反复免费触达；近年这对二分从「对立」演化为「全域协同」，但「自主权」这条轴没变。
  • 流量池 / 蓄水养鱼（mental model）: 私域人把流量当成「要蓄进池子、反复经营」的对象而非「这次能转化多少」的一次性曝光——但「建了群 / 加了好友」只是蓄了水，**没有运营动作的池是死水**；价值在「蓄水—养鱼—捕鱼」的循环，不在池子大小

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**设标签维度**：定义标签体系——基础标签（地域 / 年龄）+ 行为标签（浏览轨迹 / 咨询偏好 / 互动频率）+ 偏好标签；区分「自动标签」（系统按行为 / 购买记录生成）和「手动标签」（一线客服按沟通补充）。who: 操盘手设计、客服 + 系统共同打标。(evidence: [T03-S004])"
  "**给存量用户打标**：把已有私域用户按标签体系打标，让「面目模糊的池子」变成「可识别的人」。(evidence: [T03-S004])"
  "**分层**：用 RFM 等模型把用户分层——典型如 RFM 三维各 1-5 分合成 15 分模型，分高价值 / 潜力 / 活跃 / 沉默 / 低价值五层；或按消费金额分银 / 金 / 铂等会员等级。(evidence: [T03-S004])"
  "**分层差异化触达 SOP**：为每一层配不同动作——如「活跃客户（30 天内购买）3 天后发产品使用技巧 + 激励」「沉睡客户（60 天以上未购）发个性化 1v1 跟进 + 专属唤回礼包」。(evidence: [T03-S003])"
  "**搭会员 / 复购机制**：用等级 / 积分 / 储值 / 专属权益设计复购驱动——不同等级配不同服务、激励和权益。(evidence: [T03-S003])"
  "**数据化复盘**：盯各层转化 / 复购数据，迭代标签体系和分层动作。"
)
declare -a FAILURE_MODES=(
  "**全员一套话术**: 触发原因 = 没打标 / 没分层，或分了不用。怎么避免 = 标签体系 + 分层是「私域精细化」的第一刀，分层后动作必须差异化。"
  "**会员体系做成复杂积分游戏**: 触发原因 = 机制设计自嗨。怎么避免 = 以「用户算得清、感受得到」为准绳，宁简勿繁。"
  "**CLI 化暗示 (v0.6+)**: Treat the whole user pool as one audience and broadcast one script to everyone — high-value buyers and coupon-hunters get the same message, conversion stays flat. 先打标 + 分层，再让每层动作差异化。"
  "**CLI 化暗示 (v0.6+)**: Copy retail RFM thresholds directly without calibrating to your category's purchase cycle — your \"sleeping customer\" definition is wrong, win-back campaigns misfire. 按自己品类购买周期校准 RFM 阈值。"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "1-10-walkthrough"
fi
